    {"id": "ex-mod18-2", "type": "quiz", "question": "Quelle paire de registres est utilisée pour stocker le résultat massif de 128-bits d'une multiplication 64-bits (`mul`) ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "RCX et R8"}, {"id": "b", "text": "RAX et RBX"}, {"id": "c", "text": "RDX et RAX (RDX:RAX)"}], "correctId": "c", "explanation": "L'instruction `mul` met implicitement les bits de poids fort dans RDX et les bits de poids faible dans RAX."}},
