    {"id": "ex-mod18-5", "type": "quiz", "question": "Quelle est la différence entre les instructions de saut `ja` et `jg` ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "`ja` est pour les entiers Non-Signés, `jg` pour les entiers Signés."}, {"id": "b", "text": "`ja` saute en avant, `jg` saute en arrière."}, {"id": "c", "text": "Il n'y a aucune différence."}], "correctId": "a", "explanation": "Jump Above (`ja`) vérifie le Carry Flag (Non-Signé). Jump Greater (`jg`) vérifie l'Overflow Flag et le Sign Flag (Signé)."}},
    {"id": "ex-mod18-6", "type": "quiz", "question": "Pourquoi préfère-t-on souvent utiliser un 'Conditional Move' (cmov) plutôt qu'un saut conditionnel (je, jne) ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Parce qu'il évite de casser le pipeline d'instructions en cas de mauvaise prédiction de branchement."}, {"id": "b", "text": "Parce qu'il consomme moins de mémoire."}, {"id": "c", "text": "Parce qu'il peut exécuter deux sauts en même temps."}], "correctId": "a", "explanation": "Le Branch Misprediction coûte environ 15-20 cycles CPU. Le cmov est exécuté inconditionnellement, préservant la vitesse."}},
    {"id": "ex-mod18-7", "type": "drag-drop", "question": "Étapes de l'appel d'une fonction (Caller/Callee)", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "Mettre les arguments dans RDI, RSI (Caller)"}, {"id": "2", "text": "Instruction CALL (pousse RIP sur la pile)"}, {"id": "3", "text": "Prologue de la fonction (push rbp; mov rbp, rsp)"}, {"id": "4", "text": "Épilogue et RET (pop RIP)"}], "correctOrder": ["1", "2", "3", "4"], "instruction": "Ordonnez les étapes chronologiques d'un appel complet.", "explanation": "C'est la danse classique de la pile d'exécution en x86-64."}},
    {"id": "ex-mod18-8", "type": "fill-blank", "question": "Les divisions capricieuses", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "; Avant de faire un 'div rbx' (division de RAX par RBX),\n; il faut absolument mettre à zéro le registre supérieur __BLANK__\nmov __BLANK__, 0\ndiv rbx", "blanks": [{"id": "1", "answer": "rdx", "hint": "Le même registre utilisé par 'mul'."}, {"id": "2", "answer": "rdx", "hint": "Idem."}], "explanation": "L'instruction `div` prend le dividende combiné RDX:RAX. Si RDX contient des ordures (Garbages), le programme plantera (Floating Point Exception)."}},
    {"id": "ex-mod18-9", "type": "quiz", "question": "À quoi sert l'instruction `lea` (Load Effective Address) en dehors de la manipulation de pointeurs ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "À faire des mathématiques rapides (additions/multiplications) en un seul cycle sans affecter les flags."}, {"id": "b", "text": "À appeler l'OS."}, {"id": "c", "text": "À déréférencer un pointeur NULL."}], "correctId": "a", "explanation": "Exemple : `lea rax, [rbx + rcx*4]` calcule une valeur mathématique purement arithmétique et la stocke dans RAX ultra rapidement."}},
    {"id": "ex-mod18-10", "type": "code-correction", "question": "Nettoyer un registre", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "mov rax, 0", "correctCode": "xor eax, eax", "hints": ["L'opération logique XOR est la plus efficace pour mettre à zéro."], "explanation": "`xor eax, eax` est la norme : il prend moins d'octets en mémoire (2 octets) et brise les dépendances dans le CPU, le rendant plus rapide qu'un simple `mov`."}}
