# --- MODULE 20 : L'Appel Système ---
exercises.extend([
    {"id": "ex-mod20-1", "type": "quiz", "question": "Quel registre contient le numéro du service système (ex: 1 pour sys_write) avant d'appeler l'OS sous Linux 64-bits ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "RDI"}, {"id": "b", "text": "RAX"}, {"id": "c", "text": "RCX"}], "correctId": "b", "explanation": "RAX définit toujours l'identifiant (ID) de l'appel système que vous souhaitez réaliser."}},
    {"id": "ex-mod20-2", "type": "quiz", "question": "Où devez-vous placer le code de retour d'un programme pour le syscall 'exit' ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Dans RDI (Le 1er argument)."}, {"id": "b", "text": "Dans RAX."}, {"id": "c", "text": "Sur la pile."}], "correctId": "a", "explanation": "Comme pour une fonction classique, RDI représente le premier paramètre du syscall (le code d'erreur)."}},
    {"id": "ex-mod20-3", "type": "quiz", "question": "Quelle instruction x86-64 déclenche le passage du User-Space au Kernel-Space sous Linux ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "int 0x80"}, {"id": "b", "text": "syscall"}, {"id": "c", "text": "call kernel"}], "correctId": "b", "explanation": "L'instruction moderne est `syscall`. Historiquement sur 32-bits, on utilisait l'interruption logicielle `int 0x80`."}},
    {"id": "ex-mod20-4", "type": "fill-blank", "question": "Écrire dans le terminal", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "mov rax, 1      ; sys_write\nmov __BLANK__, 1      ; file descriptor (1 = stdout)\nmov rsi, msg    ; buffer\nmov rdx, 13     ; taille\nsyscall", "blanks": [{"id": "1", "answer": "rdi", "hint": "Le registre du 1er argument."}], "explanation": "RDI prend toujours le File Descriptor (0=stdin, 1=stdout, 2=stderr)."}},
    {"id": "ex-mod20-5", "type": "quiz", "question": "Comment le noyau Linux retourne-t-il le résultat ou le statut du syscall (ex: sys_read) ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Dans RDI."}, {"id": "b", "text": "Dans RAX."}, {"id": "c", "text": "Il n'y a pas de retour."}], "correctId": "b", "explanation": "Le noyau remplace le numéro de syscall dans RAX par la valeur de retour (ex: nombre d'octets lus, ou une erreur négative)."}},
    {"id": "ex-mod20-6", "type": "quiz", "question": "Pourquoi les registres RCX et R11 sont-ils 'détruits' (écrasés) silencieusement après l'instruction `syscall` ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Le processeur les utilise matériellement pour sauvegarder l'adresse de retour (RIP) et l'état des flags avant de sauter dans le noyau."}, {"id": "b", "text": "C'est un bug de Linux."}, {"id": "c", "text": "Ils servent à transmettre des mots de passe."}], "correctId": "a", "explanation": "L'instruction CPU `syscall` écrase RCX avec l'adresse de retour et R11 avec le RFLAGS, évitant ainsi des accès lents à la pile."}},
    {"id": "ex-mod20-7", "type": "drag-drop", "question": "Les Registres de l'Appel Système", "difficulty": "hard", "xpReward": 50, "data": {"items": [{"id": "1", "text": "RAX (Numéro du Syscall)"}, {"id": "2", "text": "RDI (Arg 1)"}, {"id": "3", "text": "RSI (Arg 2)"}, {"id": "4", "text": "RDX (Arg 3)"}, {"id": "5", "text": "R10 (Arg 4)"}], "correctOrder": ["1", "2", "3", "4", "5"], "instruction": "Ordonnez les registres selon la convention d'Appel Système Linux x86-64.", "explanation": "Attention : contrairement à l'ABI C (qui utilise RCX pour l'arg 4), le Syscall utilise R10 car RCX est détruit !"}},
    {"id": "ex-mod20-8", "type": "fill-blank", "question": "Syscall vDSO (Virtual Dynamically Shared Object)", "difficulty": "hard", "xpReward": 50, "data": {"codeTemplate": "; L'OS mappe une petite zone mémoire partagée dans chaque processus pour éviter certains syscalls lents.\n; Typiquement, la fonction __BLANK__ (heure du système) l'utilise.", "blanks": [{"id": "1", "answer": "gettimeofday", "hint": "Prendre le temps."}], "explanation": "Récupérer l'heure des millions de fois par seconde crasherait le système si on devait faire un Context Switch à chaque fois. Le vDSO permet de lire la mémoire du Kernel directement depuis l'espace utilisateur sans ralentissement."}},
    {"id": "ex-mod20-9", "type": "quiz", "question": "Comment gérez-vous une erreur retournée par un syscall (comme Fichier introuvable sur sys_open) ?", "difficulty": "hard", "xpReward": 50, "data": {"choices": [{"id": "a", "text": "Le noyau lève une exception C++."}, {"id": "b", "text": "Le programme plante avec une SEGFAULT."}, {"id": "c", "text": "RAX contient une valeur négative (entre -1 et -4095) représentant le code d'erreur (errno)."}], "correctId": "c", "explanation": "En Assembleur, il faut toujours vérifier si RAX est strictement inférieur à 0. (ex: `cmp rax, 0` puis `jl erreur`)."}},
    {"id": "ex-mod20-10", "type": "code-correction", "question": "Syscall vs Fonction C", "difficulty": "hard", "xpReward": 50, "data": {"buggyCode": "mov rax, 1\nmov rdi, 1\nmov rsi, msg\nmov rdx, 10\nmov rcx, 0 ; Quatrième argument\nsyscall", "correctCode": "mov rax, 1\nmov rdi, 1\nmov rsi, msg\nmov rdx, 10\nmov r10, 0 ; Quatrième argument pour un SYSCALL\nsyscall", "hints": ["Rappelez-vous la subtile différence d'ABI entre Linux Userspace et Linux Kernelspace."], "explanation": "L'argument n°4 passe dans RCX pour une fonction normale, mais dans R10 pour un Syscall (car RCX est détruit)."}}
])

