    {"id": "ex-mod21-2", "type": "quiz", "question": "Que fait l'instruction `stosb` ?", "difficulty": "easy", "xpReward": 20, "data": {"choices": [{"id": "a", "text": "Elle écrit le contenu du registre AL à l'adresse pointée par RDI, puis incrémente RDI."}, {"id": "b", "text": "Elle lit la mémoire et la met dans AL."}, {"id": "c", "text": "Elle copie RSI vers RDI."}], "correctId": "a", "explanation": "STore String Byte. C'est le bloc de base du `memset`."}},
    {"id": "ex-mod21-3", "type": "quiz", "question": "Que fait l'instruction `movsb` ?", "difficulty": "medium", "xpReward": 30, "data": {"choices": [{"id": "a", "text": "Elle copie 1 octet de AL vers RDI."}, {"id": "b", "text": "Elle copie 1 octet de l'adresse pointée par RSI vers l'adresse pointée par RDI, puis incrémente les deux registres."}, {"id": "c", "text": "Elle copie RDI vers RSI."}], "correctId": "b", "explanation": "MOVe String Byte. C'est le cœur d'un `memcpy` natif en un seul opcode."}},
    {"id": "ex-mod21-4", "type": "fill-blank", "question": "Direction Flag", "difficulty": "medium", "xpReward": 35, "data": {"codeTemplate": "; Avant d'utiliser rep movsb, je m'assure que le parcours se fait en avançant (de gauche à droite).\n__BLANK__\nrep movsb", "blanks": [{"id": "1", "answer": "cld", "hint": "Clear Direction Flag"}], "explanation": "L'instruction 'cld' (Clear Direction Flag) met le flag DF à 0. L'instruction opposée est 'std' (Set DF) pour parcourir à l'envers."}},
